code = """import json, pandas as pd, numpy as np

# Load the data file path from previous result
file_path = var_functions.query_db:10

# Read data from file
with open(file_path, 'r') as f:
    data = json.load(f)

# Create DataFrame
df = pd.DataFrame(data)

# Convert data types - handle errors
df['Date'] = pd.to_datetime(df['Date'], errors='coerce')
df['CloseUSD'] = pd.to_numeric(df['CloseUSD'], errors='coerce')

# Filter valid data from 2000 onwards
df = df.dropna(subset=['Date', 'CloseUSD'])
df = df[df['CloseUSD'] > 0]
df = df[df['Date'] >= pd.Timestamp('2000-01-01')]

# Country mapping for each index symbol
country_map = {'NYA': 'United States', 'IXIC': 'United States', 'HSI': 'Hong Kong', '000001.SS': 'China', '399001.SZ': 'China', 'N225': 'Japan', 'N100': 'Europe', 'GDAXI': 'Germany', 'NSEI': 'India', 'GSPTSE': 'Canada', 'SSMI': 'Switzerland', 'TWII': 'Taiwan', 'J203.JO': 'South Africa'}

# Calculate dollar-cost averaging returns
results = []

for idx in sorted(df['Index'].unique()):
    sub = df[df['Index'] == idx].copy()
    
    # Need at least 12 months of data
    if len(sub) < 12:
        continue
    
    # Get first trading day of each month
    sub = sub.sort_values('Date')
    sub['YearMonth'] = sub['Date'].dt.to_period('M')
    monthly = sub.groupby('YearMonth')['CloseUSD'].first()
    
    # Skip if no data
    if len(monthly) == 0:
        continue
    
    # DCA: invest $100 each month
    invested = 0.0
    shares = 0.0
    
    for price in monthly:
        if price > 0:
            invested = invested + 100.0
            shares = shares + (100.0 / price)
    
    # Calculate returns
    final_price = sub['CloseUSD'].iloc[-1]
    final_value = shares * final_price
    return_pct = ((final_value / invested) - 1.0) * 100.0
    
    # Store results
    country = country_map.get(idx, 'Unknown')
    results.append({'Index': idx, 'Country': country, 'Return_Percent': round(return_pct, 2)})

# Sort by return percentage and get top 5
top_5 = sorted(results, key=lambda x: x['Return_Percent'], reverse=True)[:5]

# Print top 5 for debugging
print('Top 5 indices:')
for item in top_5:
    print(item)

# Return as JSON
print('__RESULT__:')
print(json.dumps(top_5))"""

